mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_company
    WHERE company_id = #{companyId}
      AND active = TRUE
)

mapper.sql:
WHERE company_id = #{companyId}

  AND active = #{active}


  AND partner_type = #{partnerType}


  AND (
      partner_role = #{partnerRole}
      OR partner_role = 'BOTH'
  )


  AND (
      partner_name LIKE CONCAT('%', #{keyword}, '%')
      OR phone LIKE CONCAT('%', #{keyword}, '%')
      OR email LIKE CONCAT('%', #{keyword}, '%')
  )

mapper.update:
UPDATE tb_trade_partner
SET
    active = #{active},
    updated_at = NOW(6)
WHERE company_id = #{companyId}
  AND partner_id = #{partnerId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM tb_trade_partner
    WHERE company_id = #{companyId}
      AND partner_name = #{partnerName}

        AND partner_id <> #{excludePartnerId}

)
